import{_ as p,o as e,c as a,e as t}from"./app-5b072fc4.js";const c={},n=t('<h1 id="不要温和地走进那个良夜" tabindex="-1"><a class="header-anchor" href="#不要温和地走进那个良夜" aria-hidden="true">#</a> <em>不要温和地走进那个良夜</em></h1><p align="right"><i>狄兰·托马斯 1914 – 1953</i></p><p>不要温和地走进那个良夜，老年应当在日暮时燃烧咆哮；怒斥，怒斥光明的消逝。</p><p>虽然智慧的人临终时懂得黑暗有理，</p><p>因为他们的话没有迸发出闪电，他们</p><p>也并不温和地走进那个良夜。</p><p>善良的人，当最后一浪过去，高呼他们脆弱的善行</p><p>可能曾会多么光辉地在绿色的海湾里舞蹈，</p><p>怒斥，怒斥光明的消逝。</p><p>狂暴的人抓住并歌唱过翱翔的太阳，</p><p>懂得，但为时太晚，他们使太阳在途中悲伤，</p><p>也并不温和地走进那个良夜。严肃的人，接近死亡，用炫目的视觉看出</p><p>失明的眼睛可以像流星一样闪耀欢欣，</p><p>怒斥，怒斥光明的消逝。</p><p>您啊，我的父亲，在那悲哀的高处。</p><p>现在用您的热泪诅咒我，祝福我吧。我求您</p><p>不要温和地走进那个良夜。怒斥，怒斥光明的消逝。</p>',17),o=[n];function _(r,s){return e(),a("div",null,o)}const h=p(c,[["render",_],["__file","01_DylanThomas.html.vue"]]);export{h as default};
